const PROVISION_INDEX=[{"id": "s1-1", "num": "§1.1", "name": "Right to Courts and Legal Remedy", "text": "Every person may seek legal remedy for any rights violation before an independent and impartial court. This right is self-executing: where the Legislature has not funded adequate legal aid, courts appoint counsel at public expense. Procedural costs"}, {"id": "s1-2", "num": "§1.2", "name": "Individual Sovereignty Floor", "text": "Every person possesses an inviolable sphere of personal sovereignty over their own life, body, and choices. Government authority operates outside this sphere. Where the boundary is disputed, the presumption runs in favor of individual liberty;"}, {"id": "s1-3", "num": "§1.3", "name": "Prohibition of Torture and Cruel Treatment", "text": "Torture and cruel, inhuman, or degrading treatment are absolutely prohibited. No person within the Republic's jurisdiction may be subjected to any such treatment. This right is non-derogable under §1.19.b."}, {"id": "s1-4", "num": "§1.4", "name": "Prohibition of Slavery and Forced Labor", "text": "Slavery, involuntary servitude, and forced labor are absolutely prohibited. Lawfully imposed prison labor and compulsory military service under the terms established by statute do not constitute forced labor under this provision. This right is"}, {"id": "s1-5", "num": "§1.5", "name": "Civil and Political Liberties", "text": "Every person holds the rights of expression, thought, conscience, religion, association, assembly, petition, and movement. Government may regulate the time, place, and manner of expression and assembly for compelling public-order purposes, subject"}, {"id": "s1-6", "num": "§1.6", "name": "Equality and Non-Discrimination", "text": "Every person is equal before the law. Government may not discriminate on the basis of race, ethnicity, sex, sexual orientation, gender identity, religion, national origin, disability, age, or economic status in the provision of any governmental"}, {"id": "s1-7", "num": "§1.7", "name": "Bodily Sovereignty and Privacy", "text": "Medical decisions are the province of the individual and their chosen provider. The state may promote public health through information, licensing, and access; it may not compel medical decisions or penalize their exercise. Every person holds the"}, {"id": "s1-8", "num": "§1.8", "name": "Property and Security of the Home", "text": "Every person holds the right to own property and to security in their home. The state may take private property for public use only upon payment of just compensation determined by independent process, not by the taking authority. The home may not be"}, {"id": "s1-9", "num": "§1.9", "name": "Democratic Participation and Family", "text": "Every citizen holds the right to vote, stand for office, and participate in the democratic processes of the Republic, subject to the eligibility requirements established in this constitution. Every person holds the right to marry and found a family,"}, {"id": "s1-10", "num": "§1.10", "name": "Right to Bear Arms", "text": "Every person holds the right to keep and bear arms for lawful purposes including self-defense. States may establish licensing and safety frameworks. No government may enact a categorical prohibition on the civilian ownership of arms. The Legislature"}, {"id": "s1-11", "num": "§1.11", "name": "Habeas Corpus", "text": "Every person detained by public authority has the right to challenge that detention before an independent and impartial court. The detaining authority must produce the person and justify the detention within the period established by statute, not to"}, {"id": "s1-12", "num": "§1.12", "name": "Rights of the Accused and Fair Trial", "text": "Every person accused of a criminal offense holds: the right to be informed promptly of the charges; the right to counsel of their choosing, or to competent, adequately resourced counsel appointed at public expense where they cannot afford"}, {"id": "s1-13", "num": "§1.13", "name": "Right to a Public Trial", "text": "Every person accused of a criminal offense has the right to a public trial before an independent and impartial court. Proceedings may be held in camera only to the minimum extent necessary to protect a compelling interest identified in advance by"}, {"id": "s1-14", "num": "§1.14", "name": "Freedom from Retroactive Criminal Law", "text": "No person may be convicted of an act that was not a criminal offense when committed, or subjected to a penalty greater than that applicable at the time of the offense. No criminal law may be applied retroactively to the disadvantage of the accused."}, {"id": "s1-15", "num": "§1.15", "name": "Double Jeopardy", "text": "No person may be tried or punished twice for the same offense following a final acquittal or conviction. Same offense means the same conduct regardless of how it is labeled or charged; the protection applies to any charge that does not require proof"}, {"id": "s1-16", "num": "§1.16", "name": "Social Assistance Floor", "text": "Every Inhabitant is entitled to access the Republic's social state systems under Article XII. No government may exclude any person from social assistance on the basis of the characteristics listed in §1.6. The Legislature establishes by statute the"}, {"id": "s1-17", "num": "§1.17", "name": "Education", "text": "Every child has the right to education adequate to enable full civic participation. The state must ensure this education is available and accessible. Parents hold the right to direct the education of their children within the framework of public"}, {"id": "s1-18", "num": "§1.18", "name": "Environmental Obligations", "text": "Government holds an obligation not to cause environmental harm to persons within its jurisdiction through its own actions or through the actions of those it licenses. The Legislature establishes by statute the framework for environmental protection,"}, {"id": "s1-19", "num": "§1.19", "name": "Emergency Derogation", "text": "No emergency — however severe — suspends the Individual Sovereignty Floor in full. Temporary derogation of certain rights is permitted only under the strict conditions of this section; the rights enumerated in §1.19.b may not be derogated."}, {"id": "s1-19-a", "num": "§1.19.a", "name": "Emergency Derogation — Declaration Requirements", "text": "Emergency derogation of Article I rights requires a declaration specifying the nature of the emergency, which rights are limited, the geographic scope, and the duration; blanket declarations are constitutionally invalid. The declaration is published"}, {"id": "s1-19-b", "num": "§1.19.b", "name": "Non-Derogable Rights", "text": "These six rights are absolute: the prohibition on torture (§1.3); slavery (§1.4); habeas corpus (§1.11); the right to a public trial (§1.13); no retroactive punishment (§1.14); and non-refoulement (§1.21). No emergency declaration, executive order,"}, {"id": "s1-19-c", "num": "§1.19.c", "name": "Monitor Continuity", "text": "The three Monitors continue to operate with full constitutional authority throughout any emergency — they cannot be suspended or have their mandate reduced by emergency declaration."}, {"id": "s1-19-d", "num": "§1.19.d", "name": "Automatic Expiry and Judicial Review", "text": "Emergency measures lapse automatically at the expiry of the Declaration. The Legislature may, before a Declaration expires, extend it for one additional period not to exceed 60 days by 2/3 of both chambers in a concurrent vote; the extension is"}, {"id": "s1-19-e", "num": "§1.19.e", "name": "No Permanent Emergency", "text": "No emergency measure may be made permanent by legislative act. Every emergency measure lapses automatically at the expiry of the Declaration unless re-enacted through the ordinary legislative process. The Legislature may not re-declare an emergency"}, {"id": "s1-20", "num": "§1.20", "name": "Right to Seek Asylum", "text": "Every person who reaches the Republic's jurisdiction has the right to claim asylum and have that claim determined by an independent process under §6.3. The manner of entry does not affect this right. An asylum seeker is an Inhabitant of the Republic"}, {"id": "s1-21", "num": "§1.21", "name": "Non-Refoulement", "text": "No person within the Republic's jurisdiction may be returned, expelled, or extradited to any territory where they face genuine risk of persecution, torture, or deprivation of life. This protection applies regardless of the person's status, conduct,"}, {"id": "s2-1", "num": "§2.1", "name": "The Legat Consul — Domain and Term", "text": "To hold the office of Legat Consul, a person must have been a citizen for at least 7 years at the time of taking office and must hold no federal felony conviction. No other eligibility requirement applies. The Legat Consul holds enumerated authority"}, {"id": "s2-2", "num": "§2.2", "name": "Military Authorization Framework", "text": "The Legat Consul may use military force in immediate response to an active or imminent attack on Republic territory, citizens abroad, or treaty allies. Beyond immediate response, all use of military force requires legislative authorization. The"}, {"id": "s2-3", "num": "§2.3", "name": "Consular Intelligence and Veto", "text": "The Legat Consul directs foreign intelligence. No intelligence operation may be conducted against Republic citizens within Republic territory on the Legat Consul's authority; such operations require independent judicial authorization. The Legat"}, {"id": "s2-4", "num": "§2.4", "name": "Consular Domain Operations", "text": "The Legat Consul negotiates and concludes trade agreements. Civic Consul written concurrence is required only for provisions imposing national treatment obligations within Republic territory, provisions requiring new domestic legislation, or"}, {"id": "s2-5", "num": "§2.5", "name": "The Civic Consul — Domain and Term", "text": "The Civic Consul holds residual executive authority over all functions not enumerated to the Legat Consul. To hold the office of Civic Consul, a person must have been a citizen for at least 7 years at the time of taking office and must hold no"}, {"id": "s2-6", "num": "§2.6", "name": "Constructive Vote of No Confidence", "text": "The Civic Consul is accountable to the Assembly. The Assembly may remove the Civic Consul only through a constructive vote of no confidence: a single vote that simultaneously removes the sitting Civic Consul and installs a named replacement, by"}, {"id": "s2-6-a", "num": "§2.6.a", "name": "Government Formation", "text": "The Assembly elects the Civic Consul by absolute majority within the period defined by statute following any general election or vacancy; where no statutory period has been established, the constitutional default is 21 days. If the Assembly does not"}, {"id": "s2-6-b", "num": "§2.6.b", "name": "Temporary Incapacity", "text": "Where the Civic Consul is temporarily unable to exercise authority, the Civic Consul’s designated Acting Civic Consul serves with authority limited to maintaining existing policy and emergency functions. Acting status ends when the Civic Consul"}, {"id": "s2-7", "num": "§2.7", "name": "Civic Consul Legislative Instruments", "text": "Where the Civic Consul withholds assent from a bill passed by both chambers, the Civic Consul exercises a suspensive veto by returning the bill to the Legislature within the period defined by statute with a written statement of objection specifying"}, {"id": "s2-8", "num": "§2.8", "name": "Duty of Refusal", "text": "No civil servant, military member, or person acting under direct federal authorization in the performance of a specific federal function may comply with an order from either executive that would require violation of any constitutional provision or"}, {"id": "s2-9", "num": "§2.9", "name": "Legat Consul Succession and Incapacity", "text": "Full succession activates on the Legat Consul’s death, resignation, removal, or certified permanent incapacity. The Senate Speaker holds the office of Legat Consul from the moment the triggering event is published to the NRS — no active assumption"}, {"id": "s2-10", "num": "§2.10", "name": "Executive Transparency", "text": "Both executives must publish all official acts — orders, certifications, vetoes, objections, determinations, and refusals to certify — to the NRS within the period defined by statute. No executive may classify, delay, or suppress publication of an"}, {"id": "s2-11", "num": "§2.11", "name": "Emergency Governance", "text": "Where the Assembly is unable to function for an extended period — as defined by statute; in the absence of a statutory definition, the constitutional floor is 30 consecutive days during which the Assembly cannot achieve quorum — the Senate may"}, {"id": "s2-12", "num": "§2.12", "name": "Clemency", "text": "Each executive holds clemency authority within their own domain only. Consular clemency covers military law and national security offenses. Civic Consul clemency covers domestic offenses. Neither may pardon offenses within the other's domain."}, {"id": "s2-13", "num": "§2.13", "name": "Consular Removal", "text": "The Legat Consul may be removed on two independent tracks. Under the legislative track, 2/3 of both chambers in a concurrent vote on grounds of constitutional breach, demonstrated permanent incapacity, or conviction for a disqualifying offense."}, {"id": "s2-14", "num": "§2.14", "name": "Council of Ministers", "text": "The Council of Ministers comprises the Legat Consul's domain officers and the Civic Consul's ministers meeting jointly as a standing cross-executive coordination body. The Council is the primary forum for matters that cross executive domains. The"}, {"id": "s2-14-a", "num": "§2.14.a", "name": "Cross-Domain Emergency Lead", "text": "In a cross-domain emergency requiring unified operational authority, either executive may propose a temporary operational lead designation. Concurrence of both executives makes it effective and is published to the NRS. Where the executives cannot"}, {"id": "s2-14-b", "num": "§2.14.b", "name": "Coordination Failure", "text": "Where both executives are acting within their domains but their actions are materially incompatible, either may declare a coordination failure by NRS notice. The Legislature may resolve the deadlock by concurrent resolution. Where the Legislature"}, {"id": "s2-15", "num": "§2.15", "name": "Constitutional Continuity", "text": "Where conflict between constitutional actors creates a risk of suspension of lawful governance or constitutionally mandated essential services, the constitutional default is continuity at existing scope pending formal resolution. No constitutional"}, {"id": "s2-16", "num": "§2.16", "name": "Federal Prosecution", "text": "The Civic Consul is responsible for the enforcement of federal law and sets general prosecution policy. The Legislature shall by statute establish a Federal Prosecution Service independent in the exercise of individual prosecutorial decisions. The"}, {"id": "s3-1", "num": "§3.1", "name": "The Legislature", "text": "The Legislature comprises two chambers: the Assembly and the Senate. All legislation originates in the Assembly. The Senate reviews, may amend within the subject matter of the bill, and must act on every Assembly-passed bill within the period"}, {"id": "s3-2", "num": "§3.2", "name": "The Assembly", "text": "The Assembly is the proportionally elected chamber. Both States and Territories send voting members. Seats are allocated by the Webster method based on population, with a minimum of one seat per State and Territory. The constituency divisor is"}, {"id": "s3-3", "num": "§3.3", "name": "Electoral Districts", "text": "States draw their own Assembly district maps subject to five criteria: population equality within reasonable tolerance; geographic contiguity; compliance with §1.6 non-discrimination; no intentional dilution of minority voting power; and reasonable"}, {"id": "s3-4", "num": "§3.4", "name": "Legislative Standards", "text": "Every bill must address a single, clearly defined subject. Any member or approval body in the legislative process may request an EM assessment of single-subject compliance, published to the NRS. The full text of every bill must be published to the"}, {"id": "s3-5", "num": "§3.5", "name": "The Senate", "text": "The Senate comprises two senators per State regardless of population, elected for six-year staggered terms. At the first Senate seating, senators are assigned to three approximately equal cohorts by public lot: the first cohort serves an initial"}, {"id": "s3-6", "num": "§3.6", "name": "Treaty Ratification and Withdrawal", "text": "Treaty and compact agreement ratification requires 2/3 of the full seated Senate. Where a treaty fails ratification, standalone domestic provisions may be transmitted to the Assembly as ordinary legislation unless the treaty is bilateral and its"}, {"id": "s3-7", "num": "§3.7", "name": "Legislative Process and Passage", "text": "Bills pass by absolute majority of the full seated membership of both chambers. Higher thresholds apply to constitutional amendments, veto overrides, removal proceedings, and other matters specified in this constitution. The Speaker of each chamber"}, {"id": "s3-8", "num": "§3.8", "name": "Legislative Oversight", "text": "All three Monitors have full access to legislative records, committee deliberations, voting records, and draft legislation; the Legislature may not withhold records from the Monitors. The LM publishes a constitutional compliance analysis of any"}, {"id": "s3-9", "num": "§3.9", "name": "Independent Statutory Agencies", "text": "The Legislature may establish independent agencies operating outside the authority of both executives. Where this Constitution assigns a function to an independent agency, the Legislature must establish it. Directors of constitutionally mandated"}, {"id": "s3-10", "num": "§3.10", "name": "Impeachment", "text": "The Assembly may impeach officers serving in the Legat Consular domain and inferior court judges. The Legat Consul is removed exclusively under §2.13; the Civic Consul under §2.6; SC justices under §4.3.b; legislative members by their own chamber. A"}, {"id": "s3-11", "num": "§3.11", "name": "Inviolability of Electoral Mandates", "text": "Elected constitutional officers serve their constitutionally defined terms. No act of the Legislature, either executive, any court, any Monitor, or any administrative body may shorten, suspend, or terminate an elected mandate. The only permitted"}, {"id": "s3-12", "num": "§3.12", "name": "Disqualifying Offense", "text": "A disqualifying offense, wherever that term appears in this Constitution, means a conviction for a federal felony under the laws of the Republic. No state-level or foreign conviction constitutes a disqualifying offense for constitutional purposes. A"}, {"id": "s3-13", "num": "§3.13", "name": "Continuity of Constitutionally Mandated Offices", "text": "For every office established by this Constitution with a fixed term, the confirmed or elected successor’s term begins at the precise moment the incumbent’s term concludes — no gap exists between the end of one term and the commencement of the next."}, {"id": "s3-14", "num": "§3.14", "name": "Federal Legislative Competence", "text": "The Legislature holds general authority to legislate for the peace, order, and good governance of the Republic. It may not enact legislation that destroys the capacity of States to govern themselves as self-governing communities. Where federal law"}, {"id": "s3-15", "num": "§3.15", "name": "Delegation of Authority", "text": "The Legislature may by statute delegate defined authorities within its legislative competence to the Legat Consul, the Civic Consul, or established agencies. Any delegation must specify the exact scope of authority delegated, the conditions on its"}, {"id": "s4-1", "num": "§4.1", "name": "Court Structure", "text": "The Republic's judiciary operates at three levels: district courts, appellate courts, and the Supreme Court. The Legislature may establish, abolish, and define the jurisdiction of inferior courts by statute. The abolition of an inferior court does"}, {"id": "s4-2", "num": "§4.2", "name": "Judicial Appointments and Independence", "text": "Any person meeting the basic legal qualifications defined by statute may apply to the Elections Panel; the Elections Panel enters qualifying applicants into the Judicial Pool; the JM’s ongoing audit encompasses the Judicial Pool. Exceptions to pool"}, {"id": "s4-3", "num": "§4.3", "name": "The Supreme Court", "text": "The Supreme Court consists initially of nine justices organized into three staggered classes, each serving a single non-renewable 12-year term. The Legislature may increase the number of justices by statute requiring 2/3 of both chambers; any seat"}, {"id": "s4-3-a", "num": "§4.3.a", "name": "Supreme Court Quorum", "text": "A majority of the SC’s seated justices — including any Temporary Associate Justices — constitutes quorum for ordinary decisions. Constitutional questions require a minimum of five justices regardless of total seated membership. The Legislature"}, {"id": "s4-3-b", "num": "§4.3.b", "name": "Supreme Court Justice Removal", "text": "A Supreme Court justice may be removed only for cause. Three grounds constitute sufficient cause: constitutional breach in the exercise of judicial authority, as assessed by the EM under §9.1 or as determined by the removing chambers; certified"}, {"id": "s4-4", "num": "§4.4", "name": "Supreme Court Selection", "text": "SC justices are nominated by the Civic Consul from the Judicial Pool maintained by the Elections Panel under §9.12 — any pool member meeting the statutory qualifications for Supreme Court appointment is eligible for SC nomination. The Civic Consul"}, {"id": "s4-4-a", "num": "§4.4.a", "name": "Senate Bypass — Public Confirmation", "text": "Where the LM has assessed and reported a Senate breach under §4.4, the Civic Consul may — with 2/3 Assembly consent — place the serving Temporary Associate Justice on the next federal electoral period ballot for public confirmation. Confirmation"}, {"id": "s4-5", "num": "§4.5", "name": "Judicial Review and Scope", "text": "Courts have authority to declare legislative acts, executive orders, and administrative decisions unconstitutional and void. No political actor may override a constitutional ruling. The SC identifies the constitutional defect; the Legislature may"}, {"id": "s4-6", "num": "§4.6", "name": "Judgment Recognition", "text": "Judicial judgments, official records, and authenticated documents are recognized across all jurisdictions within the Republic. A judgment valid in one jurisdiction must be recognized in all others. Non-recognition grounds are exhaustive: the issuing"}, {"id": "s4-7", "num": "§4.7", "name": "Jury Service", "text": "Citizens are required to serve on juries when called. Jury service is compensated at a rate the Legislature defines by statute. Unexcused refusal is subject to civil consequences the Legislature defines. Jury service does not constitute forced labor"}, {"id": "s5-1", "num": "§5.1", "name": "Citizenship", "text": "Citizenship is acquired by birth, by parentage, or by naturalization. A child is automatically a citizen if at least one parent is a citizen or legal resident at birth. Citizens acquire their full citizenship rights, including the right to vote and"}, {"id": "s5-1-a", "num": "§5.1.a", "name": "Naturalization and Service Path", "text": "A legal resident may earn citizenship after the continuous residency period and clean legal record established by statute, upon passing a standardized assessment of civic and constitutional proficiency established by statute. A legal resident may"}, {"id": "s5-1-b", "num": "§5.1.b", "name": "Derivative and Founding Status", "text": "A child born before a parent acquired legal residency or citizenship, who accompanies that parent to the Republic within a Legislature-defined window, receives derivative status. All individuals holding voting rights on Day Zero of ratification are"}, {"id": "s5-2", "num": "§5.2", "name": "Legal Resident Rights", "text": "Legal residents hold a Residency Credential allowing them to work, enter contracts, own property, and access social state systems under Article XII. They hold all Article I rights as Inhabitants. They do not hold federal voting rights or the right"}, {"id": "s5-3", "num": "§5.3", "name": "Custodial Care of Citizen Children", "text": "Where a parent or guardian who is the primary caregiver of a citizen child is removed from the Republic, the Republic accepts responsibility for that citizen child — housing, care, and connection to remaining family. The Republic may not separate"}, {"id": "s6-1", "num": "§6.1", "name": "The Two-Stage Immigration System", "text": "Every immigration application must clear two sequential stages: State sponsorship and federal certification. Legal residency requires passing both stages. States retain discretion over whom they sponsor but may not apply sponsorship criteria that"}, {"id": "s6-2", "num": "§6.2", "name": "Enforcement, Removal, and Appeals", "text": "Only the federal government may remove individuals from the Republic. Removal occurs only for violations of laws the Legislature has defined — executive detention without statutory basis is unlawful detention subject to habeas corpus. Federal"}, {"id": "s6-3", "num": "§6.3", "name": "Asylum and Protection", "text": "Asylum proceedings operate on a separate constitutional track from the dual-gate system. Any person who files an asylum claim under §1.21 is an Inhabitant from the date of filing — entitled to Article I protections and social state access. Claims"}, {"id": "s6-3-a", "num": "§6.3.a", "name": "Asylum Court", "text": "The Asylum Court is a federal judicial institution constitutionally independent of both executive branches. Its judges are appointed under §4.2 and hold full tenure protections. The Legislature may not establish any asylum determination body as a"}, {"id": "s6-3-b", "num": "§6.3.b", "name": "Unresolvable and Security Cases", "text": "The Legislature must define a minimum status, material conditions, and periodic judicial review for persons subject to final removal orders that cannot be executed — because the destination country will not accept them or execution would violate"}, {"id": "s6-3-c", "num": "§6.3.c", "name": "Unaccompanied Minors", "text": "An unaccompanied minor arriving in the Republic is an Inhabitant from the moment of contact and holds full §1.21 protection. A federal legal guardian must be appointed by the federal court with jurisdiction over the point of contact within 72 hours."}, {"id": "s7-1", "num": "§7.1", "name": "The Right to Vote", "text": "Every citizen holds the right to vote in federal elections and the right to have that vote counted. Government at every level is prohibited from taking any action that makes voting more difficult, less accessible, or less secure. No law, rule,"}, {"id": "s7-2", "num": "§7.2", "name": "Consular Election System", "text": "The Legat Consul is elected through two concurrent requirements: a national RCV majority and a State plurality qualification. A candidate wins outright by satisfying both. Where a candidate's national RCV majority reaches or exceeds 60% of active"}, {"id": "s7-2-a", "num": "§7.2.a", "name": "State Plurality Requirement", "text": "A candidate satisfies the State plurality requirement by receiving more first-preference votes than any other candidate in a majority of the Republic's States. The Elections Panel certifies State-by-State first-preference results as part of overall"}, {"id": "s7-3", "num": "§7.3", "name": "Federal Elections", "text": "Federal elections are held at regular intervals: Assembly elections every two years; Senate elections on the staggered six-year cycle; Consular elections every six years. All federal elections use Ranked Choice Voting — majority required, not"}, {"id": "s7-3-a", "num": "§7.3.a", "name": "Special Elections and Postponements", "text": "Special elections for vacancies are administered by the Elections Panel under procedures established by statute. Where the Elections Panel certifies that elections cannot be held across a substantial portion of the Republic due to a natural disaster"}, {"id": "s8-1", "num": "§8.1", "name": "Electoral Finance", "text": "All contributions above the de minimis threshold must be publicly disclosed to the Elections Panel and published to the NRS — anonymity in electoral finance is prohibited. Individual contributions to electoral campaigns are capped at a level defined"}, {"id": "s8-2", "num": "§8.2", "name": "Campaign Conduct", "text": "Candidates for constitutional office campaign in compliance with published Elections Panel conduct standards, which include: prohibition on impersonating other candidates; prohibition on vote suppression activities; and prohibition on interference"}, {"id": "s8-3", "num": "§8.3", "name": "Public Spectrum Access for Campaigns", "text": "Licensees operating on public broadcast spectrum — including television, radio, and licensed carriers of automated political communications — shall provide equal free access to qualified candidates during the federal electoral period. The terms and"}, {"id": "s9-1", "num": "§9.1", "name": "Three Monitors", "text": "The Republic maintains three constitutionally independent Monitors — Legislative (LM), Executive (EM), and Judicial (JM) — each selected by bodies other than those it oversees. Monitors hold an information-only mandate: they observe constitutional"}, {"id": "s9-1-a", "num": "§9.1.a", "name": "The Legislative Monitor", "text": "The LM audits the Legislature for fiscal accuracy and constitutional compliance. Responsibilities include auditing the population census for constitutional compliance; reviewing Assembly district maps against §3.3 criteria and publishing germaneness"}, {"id": "s9-1-b", "num": "§9.1.b", "name": "The Executive Monitor", "text": "The EM audits both executives and the Monetary Authority. Annual responsibilities include: military compliance assessment covering whether tier authorizations were followed, whether the §2.3 intelligence warrant requirement was maintained, and"}, {"id": "s9-1-c", "num": "§9.1.c", "name": "The Judicial Monitor", "text": "The JM audits the courts for judicial scope and independence, and conducts annual audits of the Elections Panel for electoral integrity compliance, including the administration of the Judicial Pool and all constitutional pools. The JM reviews"}, {"id": "s9-1-d", "num": "§9.1.d", "name": "Monitor General Term Expiry and Incapacity", "text": "A Monitor General’s constitutional authority terminates automatically at the moment their term expires — no further act or proceeding is required. Any official act taken after term expiry is constitutionally void. Where an unexpected vacancy arises"}, {"id": "s9-2", "num": "§9.2", "name": "Selection and Independence", "text": "Each Monitor is constituted through a process that structurally excludes the body being watched from selecting its watchers. The SC nominates the LM Monitor General, confirmed by national popular vote. The Assembly Speaker and Senate Speaker jointly"}, {"id": "s9-3", "num": "§9.3", "name": "Monitor General Selection", "text": "All Monitor General confirmations follow the same process: the nominated or lottery-selected candidate is confirmed by national popular vote at the next federal electoral period by simple majority; timing is defined by statute to ensure seamless"}, {"id": "s9-4", "num": "§9.4", "name": "Judicial Monitor Audit and Lottery Administration Mandate", "text": "The JM holds two constitutional mandates: as auditor, it monitors the court system, audits the Elections Panel’s administration of the Judicial Pool, and conducts compliance audits across compact obligations; as certification administrator, it"}, {"id": "s9-4-a", "num": "§9.4.a", "name": "Judicial Monitor General Candidate Pool", "text": "The Elections Panel maintains the JM Candidate Pool. Eligibility is limited to former Republic judges — persons who have completed judicial service on a court of record at the trial court level or above, whether in a State court or the Republic's"}, {"id": "s9-4-b", "num": "§9.4.b", "name": "Judicial Pool — SC Eligibility Criteria", "text": "The Elections Panel maintains the standing Judicial Pool. Any citizen meeting the eligibility criteria — at least 15 years of legal practice or 10 years of judicial service, no current government position, no disqualifying financial interest — may"}, {"id": "s9-5", "num": "§9.5", "name": "Monitor General Removal", "text": "For-cause removal of any Monitor General follows §9.14 Standard Track. The Judicial Track under §9.14 is additionally available where two of the three Monitors jointly assess and report for-cause grounds."}, {"id": "s9-6", "num": "§9.6", "name": "Monitor Operations", "text": "Every finding, report, and discrepancy notice must be published to the NRS permanently and free of charge; no official may suppress, delay, classify, or alter a Monitor report before publication. Monitor reports are permanently exempt from"}, {"id": "s9-9", "num": "§9.9", "name": "Monitor Removal Obstruction", "text": "No constitutional actor may obstruct or delay a Monitor’s access to records, personnel, or systems within that Monitor’s audit mandate. Obstruction of a Monitor in the performance of its mandate is a constitutional breach, published to the NRS by"}, {"id": "s9-10", "num": "§9.10", "name": "Monitor Minimum Funding Guarantee", "text": "The annual appropriation for each Monitor, the Elections Panel, and the NRS Panel may not fall below the inflation-adjusted equivalent of the prior fiscal year's funding level without a 2/3 vote of both chambers in a concurrent vote. The Monetary"}, {"id": "s9-11", "num": "§9.11", "name": "Joint Monitor Council", "text": "The three Monitor Generals jointly constitute the JMC as the standing coordination body for matters crossing Monitor jurisdictions. The JMC formally houses all jointly administered constitutional functions — including lottery draws and selection"}, {"id": "s9-11-a", "num": "§9.11.a", "name": "Institutional Compromise Protocol", "text": "Where two of the three Monitors jointly assess and report that the third is operating in demonstrable bad faith, they petition the SC directly for confirmation of the finding; the SC rules within 14 days. Upon filing the petition, the two"}, {"id": "s9-12", "num": "§9.12", "name": "Constitutional Pool Framework", "text": "The Elections Panel maintains all constitutional candidate registries and pools, including the Judicial Pool, and administers public access to their records via the NRS. Each pool is subject to ongoing Monitor audit; findings are published to the"}, {"id": "s9-13", "num": "§9.13", "name": "Registry Integrity Standards", "text": "These standards apply to all registries and candidate pools maintained under constitutional mandate. Eligibility criteria are strictly objective — years of practice or service, office status, and financial interests as defined by this Constitution"}, {"id": "s9-14", "num": "§9.14", "name": "Constitutional Officer Removal — Standard Track", "text": "This section governs for-cause removal of all constitutionally confirmed independent officers except Supreme Court justices under §4.3.b and elected executives. A concurrent resolution of 1/3 of either chamber, or two of the three Monitors jointly,"}, {"id": "s9-14-a", "num": "§9.14.a", "name": "Constitutional Officer Removal — Judicial Track", "text": "The Judicial Track is available where the Standard Track’s legislative threshold appears unreachable due to demonstrated political gridlock. Where two of the three Monitors jointly assess and report for-cause grounds and petition the SC, the SC"}, {"id": "s10-1", "num": "§10.1", "name": "National Record System", "text": "The National Record System is the permanent, tamper-evident public record of the Republic — freely accessible to every Inhabitant at no cost. Every constitutional act, order, finding, certification, designation, declaration, and determination made"}, {"id": "s10-2", "num": "§10.2", "name": "NRS and Electoral Integrity", "text": "All electoral records — voter registration, ballot counts, audit trails, certification documents — must be published to the NRS within the timeframes specified by the Elections Panel's constitutional mandate under Article XI. No classification"}, {"id": "s10-3", "num": "§10.3", "name": "Classification Criteria", "text": "Government records may be classified only on grounds the Legislature defines by statute. Classification to conceal a constitutional violation, policy disagreement, or political embarrassment is prohibited and void. The classifying authority must"}, {"id": "s10-3-a", "num": "§10.3.a", "name": "Duration Framework", "text": "No record may remain classified beyond 25 years from the date of original classification. A single 5-year extension may be granted where the responsible executive publishes a justification to the EM; the EM assesses whether the justification meets"}, {"id": "s11-1", "num": "§11.1", "name": "NRS Panel and Elections Panel", "text": "Two constitutionally independent panels — the NRS Panel and the Elections Panel — operate the Republic’s permanent record infrastructure and electoral systems respectively. The NRS Panel operates the National Record System. The Elections Panel"}, {"id": "s11-2", "num": "§11.2", "name": "NVS Properties and Voting Rights", "text": "The National Voting System must maintain three constitutionally required properties simultaneously: ballot secrecy (technically impossible to link any vote to any voter, including in post-election audits), public auditability (aggregate results"}, {"id": "s11-3", "num": "§11.3", "name": "Panel Emergency Authority", "text": "The Legislature must establish by statute a procedure for each panel to adopt temporary technical measures in response to imminent security threats or system failures within its domain; emergency measures may not change electoral rules, timelines,"}, {"id": "s12-1", "num": "§12.1", "name": "The Social State and Monetary Authority", "text": "The Republic is a social state. Every Inhabitant is entitled to conditions of life consistent with human dignity, which the Republic fulfills through three mandatory systems: universally accessible healthcare insurance; social assistance sufficient"}, {"id": "s12-2", "num": "§12.2", "name": "Fiscal Accountability", "text": "The Legislature must pass a balanced budget or publish a structural deficit justification reviewed by the MA for fiscal accuracy. Structural deficits above the threshold defined by the MA require a published plan for return to balance. Where the"}, {"id": "s12-3", "num": "§12.3", "name": "Taxing Power and National Revenue Fund", "text": "The Legislature has exclusive authority to levy taxes, duties, and tariffs by statute; no other body may impose a tax, duty, or levy. All public money received by the Republic — including tax revenue, fees, and other receipts — is deposited into the"}, {"id": "s12-4", "num": "§12.4", "name": "Ethics and Conflict of Interest", "text": "All constitutional officers must disclose all financial interests, holdings, income sources, and liabilities to the EM within the period defined by statute after taking office and annually thereafter; disclosure records are published to the NRS. Any"}, {"id": "s12-5", "num": "§12.5", "name": "National Endowment", "text": "The National Endowment is a constitutionally established reserve fund that backstops the Republic’s social state obligations under §12.1 during periods of Severe Revenue Contraction, as certified by the Monetary Authority. The Endowment operates"}, {"id": "s12-6", "num": "§12.6", "name": "Compensation of Public Officials", "text": "No government official may set their own compensation or the compensation of their direct supervisors. All official compensation is set by statute and is a public record on the NRS. The Legislature may by statute set the compensation of elected"}, {"id": "s12-7", "num": "§12.7", "name": "Internal Commerce", "text": "No State or Territory may impose requirements on goods, services, or economic activity originating in another State or Territory that are more burdensome than those applied to its own. The Legislature may establish uniform internal commerce"}, {"id": "s12-8", "num": "§12.8", "name": "Fiscal Equalization", "text": "The Legislature shall by statute establish a mechanism ensuring that every State and Territory has fiscal capacity reasonably sufficient to fulfil the Social State obligations under §12.1 and the rights guaranteed under Article I. The mechanism is"}, {"id": "s13-1", "num": "§13.1", "name": "Optional Referendum", "text": "Citizens may initiate a national referendum to repeal enacted legislation. The petition process begins within 90 days of enactment and proceeds in two phases, each authenticated through the NVS using Citizen Voting Credentials. Phase One, lasting up"}, {"id": "s13-2", "num": "§13.2", "name": "Citizen Legislative Initiative", "text": "Citizens may propose legislation directly to the Legislature. The petition process proceeds in two phases, each authenticated through the NVS using Citizen Voting Credentials. Phase One, lasting up to 10 months, requires signatures from citizens"}, {"id": "s13-3", "num": "§13.3", "name": "Electoral Supermajority Threshold", "text": "60% of votes cast is the constitutional threshold for all direct electoral supermajority determinations. This threshold applies wherever this Constitution requires a supermajority outcome in a citizen vote rather than a legislative vote: the"}, {"id": "s14-1", "num": "§14.1", "name": "Authorized Purposes for Military Force", "text": "Military force serves two authorized purposes: protection of the Republic's territory, citizens, and treaty allies; and, with legislative authorization stating the specific grounds, response to crimes against humanity as defined under international"}, {"id": "s14-2", "num": "§14.2", "name": "Defense Authorization and Allocation", "text": "Military expenditure requires legislative authorization under §14.1 and budget passage under §2.5; the Legat Consul executes that funding. Where authorization specifies categories or amounts, the Legat Consul is bound by them; otherwise, the Legat"}, {"id": "s14-3", "num": "§14.3", "name": "Military Accountability", "text": "Within the period defined by statute following legislative military authorization being renewed for a second time, the Legat Consul submits a Transition and Reconstruction Plan to the Senate specifying the Republic’s post-conflict obligations:"}, {"id": "s14-4", "num": "§14.4", "name": "Treaty-Based Military Authorization", "text": "Where an existing treaty requires military action, the Legat Consul may act immediately and must notify both chambers and the Civic Consul within 12 hours, citing the specific treaty obligation triggered. Senate ratification of a treaty by the"}, {"id": "s15-1", "num": "§15.1", "name": "Territorial Compact", "text": "A Territory operates under a Territorial Compact — the restructuring agreement under §15.4 or the incorporation agreement under §15.6 where the Territory results from one of those processes, or otherwise a standard statutory framework the"}, {"id": "s15-2", "num": "§15.2", "name": "The Statehood Audit", "text": "The pathway from Territory to State is automatic upon passing the Statehood Audit and Provisional Membership Period — no political vote is required once the audit is passed. The audit has two components: the LM audits fiscal integrity; the JM audits"}, {"id": "s15-3", "num": "§15.3", "name": "Mandatory Devolution", "text": "A State enters Mandatory Devolution upon three consecutive annual Statehood Audit findings of failure published by the LM. After each failing audit, the LM publishes an Early Warning specifying compliance requirements; the State must publish a"}, {"id": "s15-4", "num": "§15.4", "name": "Voluntary Devolution and Merger", "text": "A State may voluntarily restructure its relationship with the Republic. The process requires, first, a State referendum achieving 60% approval of eligible voters on the principle of pursuing devolution; and second, upon approval, negotiation of a"}, {"id": "s15-5", "num": "§15.5", "name": "Re-Qualification Pathway", "text": "A Territory resulting from mandatory or voluntary devolution enters the Statehood re-qualification pathway under §15.2 immediately upon the effective date of devolution. No additional political vote is required to begin the pathway. Where a defined"}, {"id": "s15-6", "num": "§15.6", "name": "Voluntary Incorporation", "text": "A sovereign entity may petition to join the Republic's constitutional framework as a Territory. The process requires a petition resolution adopted by the entity's own legislature by 2/3 majority, confirmed by a citizen referendum achieving simple"}, {"id": "s15-7", "num": "§15.7", "name": "State Immutability and Territorial Integrity", "text": "A State's constitutional boundaries are fixed. No constitutional mechanism permits a State to divide directly into two or more States — the separating portion must first become a Territory before seeking independent Statehood. The Republic's"}, {"id": "s15-8", "num": "§15.8", "name": "Local Government", "text": "Local governments — cities, counties, municipalities, and other subdivisions — receive constitutional recognition as primary points of contact between citizens and government. They are entitled to reasonable fiscal capacity to carry out their"}, {"id": "s16-1", "num": "§16.1", "name": "Acknowledgment of Prior Sovereignty", "text": "Indigenous Nations within the Republic's territory hold a distinct constitutional relationship with the Republic based on prior sovereignty. This relationship is acknowledged, not granted — the Republic's constitutional framework does not create"}, {"id": "s16-2", "num": "§16.2", "name": "Compact Formation", "text": "An Indigenous Nation may enter a compact with the Republic by submitting a compact proposal to the Senate. The Senate must within 90 days either begin compact negotiations or publish written reasons for declining; a declined proposal may be"}, {"id": "s16-3", "num": "§16.3", "name": "Rights and Governance in Compact Territories", "text": "Article I rights apply in full within all compact territories; no compact provision may limit or qualify any Article I right; where compact governance conflicts with an Article I right, Article I prevails. Indigenous Nations with compacts hold"}, {"id": "s16-4", "num": "§16.4", "name": "Compact Administration and Continuity", "text": "Each compact establishes a working mechanism for implementation and day-to-day administration in a form the parties agree. The Legat Consul designates a ministerial counterpart within the Legat Consul’s office for each compact or treaty relationship"}, {"id": "s16-5", "num": "§16.5", "name": "Federal Obligations and Emergency Rights", "text": "The Republic holds affirmative obligations to compact territories: federal education funding, healthcare access, infrastructure investment, and emergency response. These obligations are enforceable by the Nation through the compact’s dispute"}, {"id": "s16-6", "num": "§16.6", "name": "Treaty Supremacy and Continuity", "text": "All treaties entered into by predecessor governments with indigenous nations are binding obligations of the Republic. Treaty rights cannot be diminished by legislation — they must be honored, renegotiated with consent, or formally superseded by"}, {"id": "s16-7", "num": "§16.7", "name": "Indigenous Nation Status Elections", "text": "An indigenous nation recognized under this Article holds the constitutional right to initiate a status transition through its own democratic or traditional governance process. Three status options are available: (a) Continued Status — the Nation’s"}, {"id": "s16-7-a", "num": "§16.7.a", "name": "Status Election Process", "text": "A status election under §16.7 requires: (1) a decision by the nation's own governance process, meeting the standards the nation itself defines for major governance decisions; and (2) publication of the election to the NRS within the period defined"}, {"id": "s17-1", "num": "§17.1", "name": "Amendment Paths", "text": "This Constitution may be amended through the parliamentary path or through citizen initiative. No executive signature is required; no executive veto applies. Every member’s vote on any amendment is published to the NRS.\n\nA parliamentary amendment"}, {"id": "s17-2", "num": "§17.2", "name": "No Executive Veto; Amendment Takes Effect", "text": "Neither the Legat Consul nor the Civic Consul has any role in the constitutional amendment process. No signature required. No veto available. An amendment takes effect immediately upon LM certification (State Ratification), Elections Panel"}, {"id": "s17-3", "num": "§17.3", "name": "Amendment Consistency and Supremacy", "text": "An amendment that is logically inconsistent with an existing provision must either explicitly repeal the inconsistent provision or the inconsistency is treated as void. The JM publishes a consistency analysis of any proposed amendment within 30 days"}, {"id": "s17-4", "num": "§17.4", "name": "Supremacy of This Constitution", "text": "This Constitution is the supreme law of the Federated Republic. All legislative acts, executive orders, treaties, administrative decisions, and government actions must be consistent with this Constitution. Any provision inconsistent with this"}, {"id": "s18-1", "num": "§18.1", "name": "The Use Doctrine", "text": "Federal government holds no territorial sovereignty within any State or Territory. All federal property rights are functional use rights — operational control over a designated footprint for the duration of the stated function. Use rights do not"}, {"id": "s18-2", "num": "§18.2", "name": "Seat of Government", "text": "The Republic holds no territorial sovereignty at its Seat of Government. The Seat is hosted by a State or Territory selected through a competitive process defined by statute; any State or Territory may submit a bid, and the selected host must"}, {"id": "s18-3", "num": "§18.3", "name": "Operational Use Rights", "text": "When a federal function ends, the Operational Use Right terminates automatically; the federal government must publish notice of termination to the NRS within the period defined by statute, not to exceed 90 days. The land and all improvements revert"}, {"id": "s18-4", "num": "§18.4", "name": "The National Trust", "text": "The National Trust holds all federal land not conveyed by statute to States, indigenous compact territories, or private parties. Land disposal requires statute — the executive cannot convey or encumber public land unilaterally. National Trust"}, {"id": "s18-5", "num": "§18.5", "name": "Federal Property in Territories", "text": "Federal operational use rights in Territories follow the same framework as in States under §18.3 and §18.4. Where §18.4 requires host State legislative consent, that consent is not required for a Territory because Territories have no State"}, {"id": "s19-1", "num": "§19.1", "name": "Activation Threshold and Ratification", "text": "This constitution takes effect upon: (1) interim Elections Panel certification that the NVS is operational and meets §11.2; and (2) a national ratification vote achieving 60% affirmative support with at least 50% participation. Ratification creates"}, {"id": "s19-2", "num": "§19.2", "name": "Day Zero and Transition", "text": "Day Zero is the date the ratification threshold is certified as achieved. Upon ratification, all laws conflicting with the Individual Sovereignty Floor are immediately null and void; all public assets transfer to the NRS; and the 24-month Transition"}, {"id": "s19-3", "num": "§19.3", "name": "Caretaker Status", "text": "All existing government officials serve as caretakers during the Transition Window — restricted to maintaining existing services only; no new permanent legislation. Legislation enacted in violation of this restriction is void; the joint Monitor"}, {"id": "s19-4", "num": "§19.4", "name": "Pre-Constitutional Classified Documents", "text": "The Legislature must establish a Classification Review Commission within 90 days of Phase 4 activation. Where the Legislature fails to meet this deadline, the LM publishes a compliance finding to the NRS, and the LM's ongoing audit encompasses the"}, {"id": "s19-5", "num": "§19.5", "name": "Pre-Existing Obligations", "text": "The Republic assumes the public debt obligations of its predecessor government as a constitutional matter — it does not inherit a clean slate. Active military operations of the prior government continue under existing authorization until the §2.2"}, {"id": "s19-6", "num": "§19.6", "name": "Transition Territories", "text": "Territories or subdivisions meeting the Statehood Audit Competency Baseline by Phase 2 end may petition to enter as State or Territory. Those failing the Baseline enter as Territory and may begin the Statehood Audit immediately. Any territory may"}, {"id": "s19-7", "num": "§19.7", "name": "Transition Candidate Registers", "text": "The joint Monitor panel assembles the initial Candidate Registers for all constitutionally established positions before Phase 3 elections can occur. The panel performs the register-assembly and qualification review function that permanent Monitors"}, {"id": "s19-8", "num": "§19.8", "name": "Transitional Accountability Mechanism", "text": "Where a ratifying polity’s predecessor government has documented constitutional violations, the Legislature may by statute passed by 2/3 of both chambers establish a Transitional Accountability Mechanism. Such a mechanism must be time-limited — not"}, {"id": "s19-9", "num": "§19.9", "name": "Required Statutory Agency Establishment", "text": "Where this Constitution assigns a specific function to a statutory independent agency under §3.9, the Legislature must establish that agency within the following timeframes from Phase 4 activation: the civic proficiency assessment administrator"}, {"id": "s20-1", "num": "§20.1", "name": "Associated Community Status", "text": "Exclusively for sovereign entities — not a form of State or Territory status, not transitional, not incorporation. Available to sovereign nations — those that have achieved full sovereignty through a status election under §16.7 or through the"}, {"id": "s20-2", "num": "§20.2", "name": "Compact Terms and Equal Sovereignty", "text": "Equal parties; neither constitutionally superior. Observing delegates attend Assembly and Senate proceedings relevant to the compact — speaking rights, no vote, no quorum or threshold effect. The Republic may not impose its constitutional governance"}, {"id": "s20-3", "num": "§20.3", "name": "Compact Conditions and Compliance", "text": "No compact may be entered or ratified with any entity whose governance practices include, authorize, or systematically permit violations of any of the non-derogable rights established in §1.19.b, committed against any person within its jurisdiction."}, {"id": "s20-4", "num": "§20.4", "name": "Sovereign Mobility", "text": "The Associated Community may at any time, by its own democratic or traditional governance process, elect to terminate the compact and proceed as a fully independent sovereign nation. No Republic consent is required for compact termination, and the"}, {"id": "s20-5", "num": "§20.5", "name": "Reciprocal Obligations and Review", "text": "The compact must specify with particularity the reciprocal obligations of both parties and the review mechanism. The Associated Community holds obligations to the Republic as well as rights from it. Review must be scheduled at regular intervals"}, {"id": "s20-6", "num": "§20.6", "name": "Compact Ratification", "text": "A compact with an Associated Community requires Senate ratification by 2/3 of full seated membership, consistent with the treaty ratification threshold under §3.6. Both executives must transmit the proposed compact to the Senate simultaneously with"}, {"id": "s20-7", "num": "§20.7", "name": "Compact Continuity", "text": "Compacts in force at the time of any government transition continue without interruption and bind successive governments of the Republic. No election result, change in the Republic's internal constitutional arrangements, or government transition"}];